@keyframes beam-flow {
  from {
    transform: translateX(0px);
  }
  to {
    transform: translateX(10px);
  }
}

.beam-line {
  will-change: transform;
  animation: beam-flow 1s linear infinite;
}

@keyframes beam-dash {
  from {
    stroke-dashoffset: 10;
  }
  to {
    stroke-dashoffset: 0;
  }
}

.beam-diagonal {
  will-change: stroke-dashoffset;
  animation: beam-dash 1s linear infinite;
}

import "./logo-cloud-section-v2.css";

export const CARD_H = 64;
export const CARD_GAP = 20;
export const FAN_W = 88;

const STACK_H = CARD_H * 3 + CARD_GAP * 2;
const Y_TOP = CARD_H / 2;
const Y_MID = CARD_H + CARD_GAP + CARD_H / 2;
const Y_BOT = CARD_H * 2 + CARD_GAP * 2 + CARD_H / 2;

export function HorizontalBeam() {
  return (
    <div className="w-16 shrink-0 overflow-hidden text-foreground/30 dark:text-foreground/50">
      <svg width="100%" height="6" style={{ overflow: "visible" }}>
        <g className="beam-line">
          <line
            x1="-10"
            y1="3"
            x2="9999"
            y2="3"
            stroke="currentColor"
            strokeWidth="2"
            strokeDasharray="3 7"
            strokeLinecap="round"
          />
        </g>
      </svg>
    </div>
  );
}

export function FanBeams() {
  return (
    <svg
      width={FAN_W}
      height={STACK_H}
      viewBox={`0 0 ${FAN_W} ${STACK_H}`}
      xmlns="http://www.w3.org/2000/svg"
      className="shrink-0 text-foreground/30 dark:text-foreground/50"
    >
      <line x1="0" y1={Y_MID} x2={FAN_W} y2={Y_TOP} stroke="currentColor" strokeWidth="2" strokeDasharray="3 7" strokeLinecap="round" className="beam-diagonal" />
      <line x1="0" y1={Y_MID} x2={FAN_W} y2={Y_MID} stroke="currentColor" strokeWidth="2" strokeDasharray="3 7" strokeLinecap="round" className="beam-diagonal" />
      <line x1="0" y1={Y_MID} x2={FAN_W} y2={Y_BOT} stroke="currentColor" strokeWidth="2" strokeDasharray="3 7" strokeLinecap="round" className="beam-diagonal" />
    </svg>
  );
}

"use client";

import { useEffect, useState } from "react";
import { UserPlus, Settings, Rocket } from "lucide-react";

const STEPS = [
  { label: "Sign Up",   Icon: UserPlus },
  { label: "Configure", Icon: Settings },
  { label: "Launch",    Icon: Rocket },
];

export function CyclingBadge() {
  const [index, setIndex] = useState(0);
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    let timeoutId: ReturnType<typeof setTimeout>;
    const interval = setInterval(() => {
      setVisible(false);
      timeoutId = setTimeout(() => {
        setIndex((i) => (i + 1) % STEPS.length);
        setVisible(true);
      }, 200);
    }, 2000);
    return () => {
      clearInterval(interval);
      clearTimeout(timeoutId);
    };
  }, []);

  const { label, Icon } = STEPS[index];

  return (
    <div className="shrink-0 flex items-center justify-center gap-2 rounded-full border border-border bg-background px-4 py-2 shadow-sm min-w-[120px]">
      <span
        className="flex items-center gap-2 transition-all duration-200"
        style={{
          opacity: visible ? 1 : 0,
          transform: visible ? "translateY(0)" : "translateY(6px)",
        }}
      >
        <Icon className="w-4 h-4 shrink-0 text-foreground" />
        <span className="text-sm font-medium text-foreground whitespace-nowrap">
          {label}
        </span>
      </span>
    </div>
  );
}

import type { SVGProps } from "react";

const Vercel = (props: SVGProps<SVGSVGElement>) => (
  <svg {...props} viewBox="0 0 256 222" preserveAspectRatio="xMidYMid">
    <path d="m128 0 128 221.705H0z" />
  </svg>
);

export { Vercel };
